/* This pass counts the number of basic blocks in each function and
   reports the count via dump_file when dumping is enabled.  It is a
   minimal, read-only GIMPLE pass that demonstrates the required
   GCC pass infrastructure:

     1. A pass_data struct describing pass metadata.
     2. A class inheriting from gimple_opt_pass with gate() and execute()
        virtual method overrides.
     3. A make_pass_count_bbs() factory function for pass registration.
     4. Use of dump_file for debug output.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "cgraph.h"
#include "basic-block.h"

namespace {

/* pass_data for the count-bbs pass.  The name "count_bbs" is used as a
   fragment of the dump file name (e.g. foo.c.123t.count_bbs).  */

const pass_data pass_data_count_bbs =
{
  GIMPLE_PASS,          /* type */
  "count_bbs",          /* name */
  OPTGROUP_NONE,        /* optinfo_flags */
  TV_NONE,              /* tv_id */
  PROP_cfg,             /* properties_required */
  0,                    /* properties_provided */
  0,                    /* properties_destroyed */
  0,                    /* todo_flags_start */
  0,                    /* todo_flags_finish */
};

/* The pass class.  Inherits from gimple_opt_pass as required by the
   GCC pass infrastructure for GIMPLE-level optimization passes.  */

class pass_count_bbs : public gimple_opt_pass
{
public:
  pass_count_bbs (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bbs, ctxt)
  {}

  /* opt_pass methods: */

  /* gate() controls whether the pass runs.  We always run this pass
     so that basic-block counts are always available in dumps.  */
  bool gate (function *) final override
  {
    return true;
  }

  /* execute() is the main body of the pass.  It counts the basic blocks
     in the current function and reports the result to dump_file.  */
  unsigned int execute (function *fun) final override
  {
    int num_bbs = n_basic_blocks_for_fn (fun);

    if (dump_file)
      fprintf (dump_file,
	       "Function '%s' has %d basic block(s).\n",
	       function_name (fun),
	       num_bbs);

    return 0;
  }

}; // class pass_count_bbs

} // anon namespace

/* Factory function used when registering the pass with the pass manager
   (see passes.def / passes.cc).  Follows the make_pass_* naming
   convention established in gcc/tree-pass.h and used throughout GCC,
   e.g. make_pass_dce() in gcc/tree-ssa-dce.cc.  */

gimple_opt_pass *
make_pass_count_bbs (gcc::context *ctxt)
{
  return new pass_count_bbs (ctxt);
}

